public int minimumTotal(List> triangle) {
    if (triangle == null || triangle.isEmpty()) return 0;

    int n = triangle.size();
    int[] dp = new int[n];

    // Initialize with last row
    for (int i = 0; i < n; i++) {
        dp[i] = triangle.get(n - 1).get(i);
    }

    // Bottom-up approach
    for (int i = n - 2; i >= 0; i--) {
        for (int j = 0; j <= i; j++) {
            dp[j] = Math.min(dp[j], dp[j + 1]) + triangle.get(i).get(j);
        }
    }

    return dp[0];
}
